// ============================================
// STEP 1: Validate & Prepare Input Image
// ============================================
const body = $input.first().json.body || $input.first().json;

if (!body.image) {
  throw new Error('No image provided. Send { "image": "base64_or_data_uri" }');
}

// Clean base64 - strip data URI prefix if present
let imageData = body.image;
let mimeType = 'image/jpeg';

if (imageData.startsWith('data:')) {
  const parts = imageData.match(/^data:([^;]+);base64,(.+)$/);
  if (parts) {
    mimeType = parts[1];
    imageData = parts[2];
  }
}

// Remove any whitespace/newlines from base64
imageData = imageData.replace(/\s/g, '');

// Validate base64 length (reject files > 10MB)
const sizeBytes = (imageData.length * 3) / 4;
if (sizeBytes > 10 * 1024 * 1024) {
  throw new Error('Image too large. Maximum 10MB.');
}

const pose = body.pose || 'front';
const background = body.background || 'white';
const isRegenerate = body.regenerate === true;
const previousAnalysis = body.previousAnalysis || null;

return [{
  json: {
    image: imageData,
    mimeType: mimeType,
    pose: pose,
    background: background,
    isRegenerate: isRegenerate,
    previousAnalysis: previousAnalysis
  }
}];

