// ============================================
// STEP 2: Build Ultra-Detailed Generation Prompt
// Using Master Prompt Engineering from reference
// ============================================
const analysisResponse = $input.first().json;
const settings = $('Prepare Image').first().json;

// Parse garment analysis
let g;
try {
  const raw = analysisResponse.candidates[0].content.parts[0].text;
  const cleaned = raw.replace(/```json|```/g, '').trim();
  g = JSON.parse(cleaned);
} catch(e) {
  // Fallback if parsing fails
  g = {
    for: 'women',
    type: 'garment',
    fabric: { primary: 'fabric', behavior: 'natural drape', weight: 'medium', texture: 'smooth' },
    color: { primary: 'as shown in reference', secondary: null, accent: null },
    pattern: { type: 'solid', description: 'as shown' },
    construction: { fit: 'regular', silhouette: 'straight', neckline: 'standard', sleeves: 'standard', length: 'standard', closure: 'none visible' },
    details: { seams: 'standard', pockets: 'none', embellishments: 'none', hem: 'clean-finished', special: 'none' }
  };
}

// Normalize fabric object (handle flat vs nested)
const fabric = typeof g.fabric === 'object' ? g.fabric : { primary: g.fabric || 'fabric', behavior: g.behavior || 'natural', weight: 'medium', texture: g.texture || 'smooth' };
const color = typeof g.color === 'object' ? g.color : { primary: g.color || 'as shown', secondary: null, accent: null };
const pattern = typeof g.pattern === 'object' ? g.pattern : { type: g.pattern || 'solid', description: g.pattern || 'solid' };
const construction = typeof g.construction === 'object' ? g.construction : { fit: g.fit || 'regular', silhouette: g.silhouette || 'straight', neckline: g.neckline || 'standard', sleeves: g.sleeves || 'standard', length: g.length || 'standard', closure: 'none' };
const details = typeof g.details === 'object' ? g.details : { seams: 'standard', pockets: 'none', embellishments: g.details || 'none', hem: 'clean', special: 'none' };

// ---- POSE LIBRARY (Biomechanical precision) ----
const poses = {
  women: {
    front: 'Standing upright with natural S-curve posture. Weight shifted slightly to left leg creating gentle hip shift. Right foot angled outward 20 degrees. Shoulders relaxed and level. Arms hanging naturally at sides with slight bend at elbows, hands resting at outer thighs with fingers relaxed and slightly curved. Head facing directly toward camera, chin level, neutral confident expression with slight natural smile. Eyes looking directly into camera lens.',
    back: 'Back facing camera, standing upright with straight spine. Feet shoulder-width apart, weight evenly distributed. Head turned 15 degrees to the right showing quarter profile of face. Arms relaxed at sides. Shoulders back naturally.',
    side: 'Body turned 45 degrees to the right from camera (three-quarter view). Head turned back toward camera showing full face. Weight on back leg, front leg slightly forward. Left hand resting on hip, right arm relaxed at side. Confident expression with chin slightly raised.'
  },
  men: {
    front: 'Standing upright with squared, confident shoulders. Feet shoulder-width apart, weight evenly distributed. Arms hanging straight down with hands relaxed at sides, fingers loosely curved. Head facing camera directly, chin raised slightly, neutral confident expression. Jaw defined, eyes looking directly into camera.',
    back: 'Back facing camera, standing straight with squared shoulders. Feet shoulder-width apart. Arms at sides. Head turned slightly showing ear and jawline.',
    side: 'Body turned 45 degrees to right. Three-quarter profile visible. Chest open, shoulders pulled back naturally. One hand casually in pocket. Head turned toward camera.'
  },
  kids: {
    front: 'Child standing naturally with playful energy. Feet slightly wider than shoulder-width. Arms loose at sides or one hand on hip. Head slightly tilted with a natural genuine smile. Eyes bright and looking at camera.',
    back: 'Child back to camera, standing naturally with arms hanging at sides. Head turned slightly showing profile.',
    side: 'Child in three-quarter view, relaxed natural posture, head turned toward camera with a smile.'
  }
};

// ---- BACKGROUND LIBRARY ----
const backgrounds = {
  white: 'Clean seamless studio background. Pure soft white (#FFFFFF) paper sweep extending from wall to floor with no visible seam or horizon line. Professional catalog photography setting. Smooth even surface.',
  grey: 'Clean seamless studio background. Neutral mid-grey paper sweep. Even lighting with no hot spots. Editorial fashion photography feel.',
  lifestyle: 'Modern minimal interior setting. Light natural oak hardwood floor. Clean white plaster wall with subtle texture. Soft natural daylight streaming from a large window on the left side. Warm atmospheric feel.'
};

const gender = (g.for || 'women').toLowerCase();
const genderKey = ['women','men','kids'].includes(gender) ? gender : 'women';
const poseKey = ['front','back','side'].includes(settings.pose) ? settings.pose : 'front';
const bgKey = ['white','grey','lifestyle'].includes(settings.background) ? settings.background : 'white';

// Model description based on gender
const modelDesc = {
  women: 'Professional female fashion model, age 22-28, natural beauty, healthy skin with realistic pores and subtle imperfections, natural body proportions, height approximately 5\'9".',
  men: 'Professional male fashion model, age 25-32, clean-shaven with defined jawline, natural skin texture, athletic build, height approximately 6\'1".',
  kids: 'Child model, age 6-10, natural healthy appearance, genuine expression, proportional build for age.'
};

// ---- BUILD THE MASTER PROMPT ----
const prompt = `Generate a photorealistic professional fashion catalog photograph. This must look IDENTICAL to a real photograph taken by a professional fashion photographer.

[MODEL]
${modelDesc[genderKey]}
Natural human anatomy with realistic skin texture, visible pores, subtle skin imperfections. No plastic or airbrushed look.

[POSE — BIOMECHANICAL PRECISION]
${poses[genderKey][poseKey]}

[GARMENT — PIXEL-LEVEL ACCURACY — THIS IS THE MOST CRITICAL SECTION]
Garment type: ${g.type}
Fabric: ${fabric.primary}, ${fabric.behavior} behavior, ${fabric.weight} weight, ${fabric.texture} texture/finish.
Primary color: ${color.primary}${color.secondary ? '. Secondary color: ' + color.secondary : ''}${color.accent ? '. Accent: ' + color.accent : ''}.
Pattern: ${pattern.type} — ${pattern.description}.
Fit: ${construction.fit}. Silhouette: ${construction.silhouette}.
Neckline: ${construction.neckline}. Sleeves: ${construction.sleeves}. Length: ${construction.length}.
Closure: ${construction.closure}.
Seams: ${details.seams}. Pockets: ${details.pockets}.
Embellishments: ${details.embellishments}.
Hem: ${details.hem}.
Special details: ${details.special}.

CRITICAL: The garment must match the reference image EXACTLY. Every stitch, every fold, every pattern element must be preserved. The fabric must behave physically correctly — showing natural wrinkles at bend points, gravity-appropriate draping, compression at tight areas, and natural movement folds.

[BACKGROUND]
${backgrounds[bgKey]}

[CAMERA & LIGHTING]
Camera: 85mm portrait lens, f/2.8 aperture, creating shallow depth of field with sharp focus on model.
Framing: Full-body shot, model centered, slight negative space above head and below feet.
Lighting: Professional three-point studio lighting setup. Key light: large softbox at 45 degrees upper-left. Fill light: reflector at lower-right. Hair light: subtle rim light from behind.
Quality: 8K resolution, photorealistic, ultra-detailed textures.
Style: High-end fashion catalog photography, similar to ZARA, H&M, or NET-A-PORTER product pages.

[ABSOLUTE RULES]
- The garment MUST match the provided reference image with maximum fidelity
- Natural human anatomy — no extra fingers, no distorted limbs
- Realistic fabric physics — the clothing must look like it exists in real 3D space
- No text, watermarks, or logos unless present on the original garment
- Professional fashion photography quality`;

return [{
  json: {
    image: settings.image,
    mimeType: settings.mimeType,
    prompt: prompt,
    garmentAnalysis: g
  }
}];

// ============================================
// STEP 3: Extract Generated Image from Response
// ============================================
const response = $input.first().json;
const garmentAnalysis = $('Build Generation Prompt').first().json.garmentAnalysis;

let imageBase64 = null;
let imageMime = 'image/png';
let textResponse = '';

try {
  const candidate = response.candidates[0];

  if (candidate.finishReason === 'SAFETY' || candidate.finishReason === 'BLOCKED') {
    throw new Error('Image generation was blocked by safety filters. Try a different garment image.');
  }

  const parts = candidate.content.parts;

  for (const part of parts) {
    if (part.inline_data && part.inline_data.data) {
      imageBase64 = part.inline_data.data;
      imageMime = part.inline_data.mime_type || 'image/png';
    }
    if (part.text) {
      textResponse = part.text;
    }
  }
} catch(e) {
  if (e.message.includes('safety') || e.message.includes('blocked')) {
    throw e;
  }

  // Check for error in response
  if (response.error) {
    throw new Error('Gemini API Error: ' + (response.error.message || JSON.stringify(response.error)));
  }

  throw new Error('Failed to parse Gemini response: ' + e.message);
}

if (!imageBase64) {
  throw new Error('Gemini did not return an image. The model may have refused or encountered an error. Response: ' + textResponse.substring(0, 200));
}

return [{
  json: {
    success: true,
    result_image: imageBase64,
    result_mime: imageMime,
    garmentAnalysis: garmentAnalysis
  }
}];
